import { calculatePlayerStats } from './task08';

describe('calculatePlayerStats', () => {
  it('counts wins, losses, draws correctly', () => {
    const result = calculatePlayerStats({
      gameResults: ['1:2:3:4-12:8', '1:2:3:4-8:12', '1:2:3:4-10:10'],
    } as any);
    expect(result.wins).toBe(1);
    expect(result.losses).toBe(1);
    expect(result.draws).toBe(1);
    expect(result.totalGames).toBe(3);
  });

  it('handles empty results', () => {
    const result = calculatePlayerStats({ gameResults: [] } as any);
    expect(result.totalGames).toBe(0);
    expect(result.winRate).toBe(0);
  });
});
